from typing import Dict, List, Any

class MockQuantumBackend:
    """Mock backend for testing quantum code."""

    def __init__(self, results: Dict[str, int] = None):
        self.results = results or {'0': 1024}
        self.executed_circuits: List[Any] = []

    def execute(self, circuit: Any, shots: int = 1024) -> Dict[str, int]:
        self.executed_circuits.append(circuit)
        return self.results.copy()

    def get_executed_count(self) -> int:
        return len(self.executed_circuits)

    def reset(self):
        self.executed_circuits.clear()

# Test
mock = MockQuantumBackend({'00': 500, '11': 500})
result = mock.execute("circuit1")
result = mock.execute("circuit2")
print(f"Executions: {mock.get_executed_count()}")
print(f"Result: {result}")
